log = logging.getLogger("mmo-server")


@dataclass
class Item:
    id: str
    name: str
    owner_id: str
    tradable: bool = True
    metadata: Dict[str, Any] = field(default_factory=dict)


@dataclass
class Player:
    id: str
    name: str
    websocket: WebSocketServerProtocol
    inventory: Set[str] = field(default_factory=set)


class GameState:
    def __init__(self) -> None:
        self.players: Dict[str, Player] = {}
        self.items: Dict[str, Item] = {}
        self.player_locks: Dict[str, asyncio.Lock] = defaultdict(asyncio.Lock)
        self.connection_to_player: Dict[WebSocketServerProtocol, str] = {}
        self.global_lock = asyncio.Lock()

    async def register_player(self, websocket: WebSocketServerProtocol, player_name: str) -> Player:
        async with self.global_lock:
            player_id = str(uuid.uuid4())
            player = Player(id=player_id, name=player_name, websocket=websocket)
            self.players[player_id] = player
            self.connection_to_player[websocket] = player_id

            starter_items = [
                Item(id=str(uuid.uuid4()), name="Gold Coin", owner_id=player_id),
                Item(id=str(uuid.uuid4()), name="Health Potion", owner_id=player_id),
                Item(id=str(uuid.uuid4()), name="Wooden Sword", owner_id=player_id),
            ]
            for item in starter_items:
                self.items[item.id] = item
                player.inventory.add(item.id)

            log.info("Registered player %s (%s)", player.name, player.id)
            return player

    async def unregister_player(self, websocket: WebSocketServerProtocol) -> None:
        async with self.global_lock:
            player_id = self.connection_to_player.pop(websocket, None)
            if not player_id:
                return
            player = self.players.pop(player_id, None)
            if player:
                log.info("Unregistered player %s (%s)", player.name, player.id)

    async def get_player_by_ws(self, websocket: WebSocketServerProtocol) -> Optional[Player]:
        player_id = self.connection_to_player.get(websocket)
        if not player_id:
            return None
        return self.players.get(player_id)

    async def create_item(self, owner_id: str, name: str, tradable: bool = True, metadata: Optional[Dict[str, Any]] = None) -> Item:
        item = Item(
            id=str(uuid.uuid4()),
            name=name,
            owner_id=owner_id,
            tradable=tradable,
            metadata=metadata or {},
        )
        async with self.player_locks[owner_id]:
            owner = self.players[owner_id]
            self.items[item.id] = item
            owner.inventory.add(item.id)
        return item

    async def transfer_items(self, from_player_id: str, to_player_id: str, item_ids: List[str]) -> Tuple[bool, str, List[Item]]:
        if from_player_id == to_player_id:
            return False, "Cannot transfer items to self", []

        ordered = sorted([from_player_id, to_player_id])
        first_lock = self.player_locks[ordered[0]]
        second_lock = self.player_locks[ordered[1]]

        async with first_lock:
            async with second_lock:
                from_player = self.players.get(from_player_id)
                to_player = self.players.get(to_player_id)

                if not from_player or not to_player:
                    return False, "Player not found", []

                transferred: List[Item] = []

                for item_id in item_ids:
                    item = self.items.get(item_id)
                    if item is None:
                        return False, f"Item not found: {item_id}", []
                    if item.owner_id != from_player_id:
                        return False, f"Ownership mismatch for item: {item_id}", []
                    if item_id not in from_player.inventory:
                        return False, f"Item missing from source inventory: {item_id}", []
                    if not item.tradable:
                        return False, f"Item not tradable: {item_id}", []

                for item_id in item_ids:
                    item = self.items[item_id]
                    from_player.inventory.remove(item_id)
                    to_player.inventory.add(item_id)
                    item.owner_id = to_player_id
                    transferred.append(item)

                return True, "Transfer successful", transferred

    async def get_inventory(self, player_id: str) -> List[Dict[str, Any]]:
        player = self.players.get(player_id)
        if not player:
            return []
        async with self.player_locks[player_id]:
            result = []
            for item_id in player.inventory:
                item = self.items.get(item_id)
                if item:
                    result.append(
                        {
                            "id": item.id,
                            "name": item.name,
                            "owner_id": item.owner_id,
                            "tradable": item.tradable,
                            "metadata": item.metadata,
                        }
                    )
            return result

    async def broadcast_to_players(self, player_ids: List[str], message: Dict[str, Any]) -> None:
        data = json.dumps(message)
        tasks = []
        for player_id in player_ids:
            player = self.players.get(player_id)
            if player:
                tasks.append(self._safe_send(player.websocket, data))
        if tasks:
            await asyncio.gather(*tasks, return_exceptions=True)

    async def _safe_send(self, websocket: WebSocketServerProtocol, data: str) -> None:
        try:
            await websocket.send(data)
        except Exception as e:
            log.warning("Send failed: %s", e)


game_state = GameState()


async def send_json(ws: WebSocketServerProtocol, payload: Dict[str, Any]) -> None:
    await ws.send(json.dumps(payload))


async def handle_register(ws: WebSocketServerProtocol, msg: Dict[str, Any]) -> Optional[Player]:
    name = msg.get("name")
    if not name or not isinstance(name, str):
        await send_json(ws, {"type": "error", "message": "Missing or invalid player name"})
        return None

    player = await game_state.register_player(ws, name)
    inventory = await game_state.get_inventory(player.id)

    await send_json(
        ws,
        {
            "type": "registered",
            "player": {
                "id": player.id,
                "name": player.name,
            },
            "inventory": inventory,
        },
    )
    return player


async def handle_get_inventory(ws: WebSocketServerProtocol, player: Player) -> None:
    inventory = await game_state.get_inventory(player.id)
    await send_json(
        ws,
        {
            "type": "inventory",
            "player_id": player.id,
            "items": inventory,
        },
    )


async def handle_create_item(ws: WebSocketServerProtocol, player: Player, msg: Dict[str, Any]) -> None:
    name = msg.get("name")
    tradable = bool(msg.get("tradable", True))
    metadata = msg.get("metadata", {})

    if not name or not isinstance(name, str):
        await send_json(ws, {"type": "error", "message": "Missing or invalid item name"})
        return
    if metadata is not None and not isinstance(metadata, dict):
        await send_json(ws, {"type": "error", "message": "Invalid metadata"})
        return

    item = await game_state.create_item(player.id, name, tradable=tradable, metadata=metadata)
    await send_json(
        ws,
        {
            "type": "item_created",
            "item": {
                "id": item.id,
                "name": item.name,
                "owner_id": item.owner_id,
                "tradable": item.tradable,
                "metadata": item.metadata,
            },
        },
    )


async def handle_trade(ws: WebSocketServerProtocol, player: Player, msg: Dict[str, Any]) -> None:
    to_player_id = msg.get("to_player_id")
    item_ids = msg.get("item_ids")

    if not to_player_id or not isinstance(to_player_id, str):
        await send_json(ws, {"type": "error", "message": "Missing or invalid to_player_id"})
        return
    if not isinstance(item_ids, list) or not all(isinstance(x, str) for x in item_ids) or not item_ids:
        await send_json(ws, {"type": "error", "message": "item_ids must be a non-empty list of strings"})
        return

    unique_item_ids = list(dict.fromkeys(item_ids))
    success, message, transferred = await game_state.transfer_items(player.id, to_player_id, unique_item_ids)

    if not success:
        await send_json(ws, {"type": "trade_result", "success": False, "message": message})
        return

    transferred_payload = [
        {
            "id": item.id,
            "name": item.name,
            "owner_id": item.owner_id,
            "tradable": item.tradable,
            "metadata": item.metadata,
        }
        for item in transferred
    ]

    await game_state.broadcast_to_players(
        [player.id, to_player_id],
        {
            "type": "trade_result",
            "success": True,
            "message": message,
            "from_player_id": player.id,
            "to_player_id": to_player_id,
            "items": transferred_payload,
        },
    )


async def handle_message(ws: WebSocketServerProtocol, raw: str) -> None:
    try:
        msg = json.loads(raw)
    except json.JSONDecodeError:
        await send_json(ws, {"type": "error", "message": "Invalid JSON"})
        return

    if not isinstance(msg, dict):
        await send_json(ws, {"type": "error", "message": "Message must be a JSON object"})
        return

    msg_type = msg.get("type")
    if not isinstance(msg_type, str):
        await send_json(ws, {"type": "error", "message": "Missing message type"})
        return

    player = await game_state.get_player_by_ws(ws)

    if msg_type == "register":
        if player is not None:
            await send_json(ws, {"type": "error", "message": "Already registered"})
            return
        await handle_register(ws, msg)
        return

    if player is None:
        await send_json(ws, {"type": "error", "message": "Register first"})
        return

    if msg_type == "get_inventory":
        await handle_get_inventory(ws, player)
    elif msg_type == "create_item":
        await handle_create_item(ws, player, msg)
    elif msg_type == "trade":
        await handle_trade(ws, player, msg)
    else:
        await send_json(ws, {"type": "error", "message": f"Unknown message type: {msg_type}"})


async def client_handler(ws: WebSocketServerProtocol) -> None:
    log.info("Client connected")
    try:
        async for message in ws:
            await handle_message(ws, message)
    except websockets.ConnectionClosed:
        pass
    except Exception as e:
        log.exception("Client handler error: %s", e)
    finally:
        await game_state.unregister_player(ws)
        log.info("Client disconnected")


async def main(host: str = "0.0.0.0", port: int = 8765) -> None:
    stop_event = asyncio.Event()

    def _stop(*_: Any) -> None:
        stop_event.set()

    loop = asyncio.get_running_loop()
    for sig in (signal.SIGINT, signal.SIGTERM):
        try:
            loop.add_signal_handler(sig, _stop)
        except NotImplementedError:
            pass

    async with websockets.serve(client_handler, host, port, max_size=2**20):
        log.info("Server listening on %s:%s", host, port)
        await stop_event.wait()
        log.info("Shutdown requested")

if __name__ == "__main__":
    asyncio.run(main())